mapper.select:
SELECT COUNT(*)
FROM FWK_USER_MENU
WHERE USER_ID = #{userId} AND MENU_ID = #{menuId}

mapper.update:
UPDATE FWK_USER_MENU
SET AUTH_CODE = #{authCode},
    FAVOR_MENU_ORDER = #{favorMenuOrder},
    LAST_UPDATE_DTIME = #{now},
    LAST_UPDATE_USER_ID = #{currentUserId}
WHERE USER_ID = #{userId} AND MENU_ID = #{menuId}

mapper.select:
SELECT AUTH_CODE
FROM FWK_USER_MENU
WHERE USER_ID = #{userId, jdbcType=VARCHAR} AND MENU_ID = #{menuId, jdbcType=VARCHAR}
